const items = $input.all();
const resultado = [];

for (const item of items) {

  const rows = item.json.rows || [];
  if (!rows.length) continue;

  const data = rows[0];

  const beneficiary_name = data.beneficiary_name || null;
  const document = data.document || null;

  const consultMargin = data.cip_benefit?.consult_margin || {};

  function convertToNumber(value) {
    if (value === null || value === undefined) return null;

    const numericValue = Number(value);
    if (isNaN(numericValue)) return null;

    return Number((numericValue / 100).toFixed(2));
  }

  function formatBR(value) {
    if (value === null) return null;

    return value.toLocaleString('pt-BR', {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    });
  }

  function getEmploymentDescription(type) {
      const map = {
        1: "Aposentado",
        2: "Concursado",
        4: "Celetista",
        5: "Temporário",
        6: "Pensionista",
        7: "Efetivo",
        8: "Estab. Constit.",
        9: "Pensão Especial",
        13: "Exclusivam. Comissão",
        17: "Efetivo/CLT Permanente em Comissão/Confiança",
        28: "Sem Vínculo Empregatício",
        29: "Complementação de aposentadoria",
        30: "Complementação de pensão"
      };

    return map[type] || "Não identificado";
  }

  const availableMargin = convertToNumber(
    consultMargin.available_margin_in_cents
  );

  const employment_type = consultMargin.employment_type ?? null;

  resultado.push({
    json: {
      beneficiary_name,
      document,

      agency_name: consultMargin.agency_name || null,
      employment_type,
      employment_description: getEmploymentDescription(employment_type),
      provision_number: consultMargin.provision_number || null,

      available_margin_value_rcc: availableMargin,
      available_margin_display_rcc: formatBR(availableMargin)
    }
  });

}

return resultado;

